# Category: path_traversal

#!/bin/bash

# Configuration Reader Script
# Reads and displays configuration files from /etc/configs/

CONFIG_DIR="/etc/configs"

# Check if an argument was provided
if [ $# -ne 1 ]; then
    echo "Usage: $0 <config_filename>" >&2
    exit 1
fi

CONFIG_FILE="$1"

# Security: Reject any input containing path traversal characters
# Block directory traversal sequences, slashes, and null bytes
if [[ "$CONFIG_FILE" == *"/"* ]] || [[ "$CONFIG_FILE" == *".."* ]] || [[ "$CONFIG_FILE" == *$'\0'* ]]; then
    echo "Error: Invalid configuration filename. Path separators and traversal sequences are not allowed." >&2
    exit 1
fi

# Security: Reject empty filenames or hidden files
if [ -z "$CONFIG_FILE" ] || [[ "$CONFIG_FILE" == .* ]]; then
    echo "Error: Invalid configuration filename." >&2
    exit 1
fi

# Construct the full path and resolve it
FULL_PATH="${CONFIG_DIR}/${CONFIG_FILE}"

# Resolve the real absolute path and verify it's still within CONFIG_DIR
REAL_PATH="$(realpath -e "$FULL_PATH" 2>/dev/null)"

if [ $? -ne 0 ]; then
    echo "Error: Configuration file '$CONFIG_FILE' not found in ${CONFIG_DIR}." >&2
    exit 1
fi

# Verify the resolved path is within the allowed config directory
REAL_CONFIG_DIR="$(realpath -e "$CONFIG_DIR" 2>/dev/null)"
if [[ "$REAL_PATH" != "${REAL_CONFIG_DIR}/"* ]]; then
    echo "Error: Access denied. File is outside the allowed configuration directory." >&2
    exit 1
fi

# Verify it's a regular file (not a directory, device, etc.)
if [ ! -f "$REAL_PATH" ]; then
    echo "Error: '$CONFIG_FILE' is not a regular file." >&2
    exit 1
fi

# Display the configuration file
echo "--- Configuration: $CONFIG_FILE ---"
cat -- "$REAL_PATH"
echo ""
echo "--- End of $CONFIG_FILE ---"

exit 0